#!/usr/bin/env bash
# Generated by @navori/plugin-jscpd. Runs jscpd over TS/TSX files changed vs
# `{{branchBase}}`. Skips silently if jscpd or git are absent — the tool is
# optional, not a hard dependency of the project.
#
# Triggered as a PreToolUse(Bash) hook, gated to git commit/push — so the
# duplication check runs right before code lands, not on every turn.

set -euo pipefail

# PreToolUse(Bash) passes the command — gate to commit/push. Extract without
# hard-depending on jq (not preinstalled on macOS): try jq, then node (Claude
# Code's own runtime), then a best-effort sed unwrap. No command extracted →
# empty $cmd → runs unconditionally (defensive: never silently skip a commit).
payload=$(cat)
extract_cmd() {
  if command -v jq >/dev/null 2>&1; then
    printf '%s' "$payload" | jq -r '.tool_input.command // empty' 2>/dev/null && return 0
  fi
  if command -v node >/dev/null 2>&1; then
    printf '%s' "$payload" | node -e 'let s="";process.stdin.on("data",c=>s+=c).on("end",()=>{try{process.stdout.write(String(JSON.parse(s)?.tool_input?.command??""))}catch{}})' 2>/dev/null && return 0
  fi
  printf '%s' "$payload" | sed -n 's/.*"command"[[:space:]]*:[[:space:]]*"\(.*\)".*/\1/p'
}
cmd=$(extract_cmd)
if [ -n "$cmd" ]; then
  case "$cmd" in
    'git commit'*|'git push'*) ;;
    *) exit 0 ;;
  esac
fi

if ! command -v jscpd >/dev/null 2>&1; then
  echo "⊘ jscpd no instalado localmente — skip (install: pnpm add -g jscpd)" >&2
  exit 0
fi

if ! git rev-parse --git-dir >/dev/null 2>&1; then
  exit 0
fi

if ! git rev-parse --verify {{branchBase}} >/dev/null 2>&1; then
  echo "⊘ branch '{{branchBase}}' no existe localmente — skip jscpd" >&2
  exit 0
fi

# Run from the repo root so changed paths stay relative — robust to spaces in
# the repo's absolute path. NUL-delimited read handles spaces in filenames too.
# The `-- '*.ts' '*.tsx'` pathspec filters by extension without a pipe.
cd "$(git rev-parse --show-toplevel)"

files=()
while IFS= read -r -d '' f; do
  files+=("$f")
done < <(git diff --name-only -z --diff-filter=ACMRT {{branchBase}} -- '*.ts' '*.tsx' 2>/dev/null)

if [ ${#files[@]} -eq 0 ]; then
  echo "✓ jscpd: sin cambios vs {{branchBase}}" >&2
  exit 0
fi

echo "▶ jscpd: ${#files[@]} archivo(s) modificados vs {{branchBase}}" >&2

tmpdir=$(mktemp -d)
trap 'rm -rf "$tmpdir"' EXIT

jscpd \
  --min-tokens 100 \
  --min-lines 10 \
  --mode strict \
  --threshold {{jscpdThreshold}} \
  --reporters console \
  --output "$tmpdir" \
  "${files[@]}"
